import{c as i,Q as r,j as l,g as e,n as t}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"出使德意志皇帝","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/59-出使德意志皇帝.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/59-出使德意志皇帝.md"}'),o={name:"research/machiavelli/machiavelli/diplomatic/lower/59-出使德意志皇帝.md"};function c(s,a,n,m,d,_){return r(),l("div",null,[...a[0]||(a[0]=[e("h1",{id:"出使德意志皇帝",tabindex:"-1"},[t("出使德意志皇帝 "),e("a",{class:"header-anchor",href:"#出使德意志皇帝","aria-label":'Permalink to "出使德意志皇帝"'},"​")],-1),e("p",null,"出使德意志皇帝 是,万一帝国会议真的做出这样的决定,那么这将对法国相当不利,而对 德意志将更加不利。引起这些猜测的原因是,法国国王在过去的8个月中 在这里派驻了2个代表,而且还在这里安排了他的两个亲信——罗赫阿尔 贝特和皮埃尔 · 路易。为了及时收到这些人的报告,国王还在此地和加 贝拉之间,或他的代表们可能去到的任何其他地方,建立了一系列正规的 邮递服务。这些人最近努力联合所有行政区,并且通过公开的或私下的金 钱收买,毒害了整个地区。通过这样的途径,他们阻止了并继续阻碍着帝 国会议通过任何对德意志有利的决议。所以,直到我离开那里为止,帝国 会议召开了许多会议,但却没有通过任何决议。确实,帝国会议还将于主 显节时在卢塞恩召开另一个会议。两个法国密使并不在那里,但是会议将 会得出什么结论还是未知数。不过,那个在弗里堡的人(我在前面提到过 的那个人),告诉我说法国国王有足够的金钱阻止帝国会议通过任何对他 不利的决议。但是,一旦罗马皇帝也有足够的金钱,他们就不能拒绝服从 他了。不过,如果那样的话,他们会尽量一边侍奉皇帝,一边不对法国表 现敌意。所有人都认为,只要皇帝不缺乏金钱,那么他也不会缺乏瑞士人 的顺从。因为他们担心,如果皇帝给他们付了钱,而他们却没有归附皇 帝,那么他们将激起帝国的敌意。他们实在不愿得罪整个德意志,这就是 他们没有公开宣布归附法国的原因。但是,他们与皇帝的意愿相左的地方 在于:他们不想反对法国,不过他们可以在其他的任何地方听命于皇帝。 另一方面,皇帝要求他们完全保持中立,或者给他提供少数人任他差遣。 但是,瑞士方面却不愿保持中立,而且希望被大规模地雇佣。同时,他们 也不愿与法国开战,除非法国国王给了他们什么特殊的理由。这就是为什 么帝国会议召开了那么多会议,却得不出任何结论的原因。而且大家也认 为,现在这个会议将像之前那些会议一样,只不过是些毫无用处的口舌之 争,而不会得出任何结论。 除了上面提到的12个行政区,还有另外2个瑞士公社,即格里松联盟 和瓦尔登联盟,都挨着意大利边境。几天前我经过弗里堡的时候,皇帝的",-1),e("p",null,"政务与外交著作 Legazioni,commissarie,scritti di governo",-1)])])}const f=i(o,[["render",c]]);export{h as __pageData,f as default};
